"use client";

import axios from "axios";
import Script from "next/script";
import { useState } from "react";

declare global {
  interface Window {
    Razorpay: any;
  }
}


export default function PaymentPage()  {
    const Amount = 100 * 100;
    const [isProcessing, setIsProcessing] = useState(false);

    const handlePAyment = async () => {
        setIsProcessing(true);

        try{
            // const response = await fetch("/api/create-order", {
            // method: "POST", body: JSON.stringify({ amount: Amount, email : localStorage.getItem("email") }),
            // headers: { "Content-Type": "application/json" },
            // });
            // const data = await response.json();

            // console.log(data);

            const user = JSON.parse(localStorage.getItem("user"));
            

            console.log("user : ", user);
            
            
            

              const options = {
                key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID,
                amount: Amount,
                currency: "INR",
                name: "Bring your Buddy",
                description: "Test Transaction",
                // order_id: data.order_id,
                handler: function (response) {
                  console.log("Payment Succeasfull", response);

                  axios.post("/api/payment", {email : user.email}).then((res) => {console.log(res.data);}).catch((err) => console.log(err));

                    axios
                      .post("/api/send-documents", {
                        email: user.email,
                        name: user.name,
                        paymentConfirmation: response.razorpay_payment_id,
                        amount: Amount,
                      })
                      .then((res) => {
                        console.log("res : ", res);

                        alert("Payment Successfull ! you can now check your email for further details");
                      })
                      .catch((err) => {
                        console.log("err : ", err);
                      });
                },
                prefill: {
                  name: "Ankita Sharma",
                  email: "ankita31.mcl@gmail.com",
                  contact: "9324567890",
                },
                theme: {
                  color: "#3399cc",
                },
              };
            const rzp1 = new window.Razorpay(options);
            rzp1.open();
        }catch(err){
            console.log(err);
        }finally{
            setIsProcessing(false);
        }
    }

    return (
        <div>
            <Script src="https://checkout.razorpay.com/v1/checkout.js"/>
            <h1>Payment Page</h1>

            <h1>Amount to pay : {Amount} INR</h1>

            <button onClick={handlePAyment} disabled={isProcessing}>
                {isProcessing ? "Processing..." : "Pay Now"}
            </button>
        </div>
    )
}